; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 3, 4, 5, 6]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="No Trespassing!"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] ! events.has(45) || WAY == "w"

[if exp='game.isFreeMode']
	[texton]
	[name n=Thief]「What the hell are you guys doing?」[k]
	The bandits attack![k]
	[textoff]
	@clf
	@monster pos=1 name=ブッシュワッカー
	@monster pos=2 name=ブッシュワッカー
	@monster pos=3 name=ブッシュワッカー
	@monster pos=4 name=ブッシュワッカー
	@monster pos=5 name=ブッシュワッカー
	@callbattle gameover=true
	@delevent
	[eventoff]
[endif]

[if exp='! game.events.has(45)']
	@addevent name=全般 num=45
	@jump storage="main01.scn" target=*cottage_2
[endif]

[texton]
I haven't collected the necklace yet. It must be in this room, so let's find it.[k]
[textoff]
@walk move=e

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@notice text="Be careful of falling when going out to the balcony."

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger
*event_5
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("life", 50)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had HP restored!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] onObjectTrigger

@barrel
@eval exp='game.curTarget.setStatus(o.倍加, true)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had attack count temporarily doubled!"'

[eventoff]
;-------------------------------------------------------------------------------
